const supabase = createClient\(process.env.NEXT_PUBLIC_SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY\);
\(async \(\) => {
  // Get smoke test config IDs
  const { data: configs } = await supabase.from\('a_sop_configs'\).select\('id'\).like\('notes', 'SMOKE TEST%'\);
  const ids = \(configs || []\).map\(c => c.id\);

  // Delete compliance rows first \(FK\)
  const { count: c1 } = await supabase.from\('b_sop_compliance_log'\).delete\({ count: 'exact' }\).in\('sop_config_id', ids\);
  console.log\('Deleted compliance rows:', c1\);

  // Delete configs
  const { count: c2 } = await supabase.from\('a_sop_configs'\).delete\({ count: 'exact' }\).like\('notes', 'SMOKE TEST%'\);
  console.log\('Deleted configs:', c2\);

  // Confirm clean
  const { count: remaining } = await supabase.from\('a_sop_configs'\).select\('id', { count: 'exact', head: true }\).like\('notes', 'SMOKE TEST%'\);
  console.log\('Remaining smoke test configs:', remaining, remaining === 0 ? '- CLEAN' : '- NOT CLEAN'\);
}\)\(\);
